function ResultCard({ data }) {
  return (
    <div className="card mt-3">
      <div className="card-body">
        <h5>{data.title}</h5>
        <p>Skills: {data.skills.join(", ")}</p>
        <span className="badge bg-success">
          Match: {data.match}%
        </span>
      </div>
    </div>
  );
}

export default ResultCard;
